    "Brojevi i redosled operacija":{"en": "Numbers and order of operations", "de": "Zahlen und Rechenreihenfolge", "fr": "Nombres et ordre des opérations", "es": "Números y orden de operaciones", "it": "Numeri e ordine delle operazioni", "ru": "Числа и порядок действий", "pt": "Números e ordem das operações"},
    "Brojevi, izrazi i jednačine":{"en": "Numbers, expressions, and equations", "de": "Zahlen, Terme und Gleichungen", "fr": "Nombres, expressions et équations", "es": "Números, expresiones y ecuaciones", "it": "Numeri, espressioni ed equazioni", "ru": "Числа, выражения и уравнения", "pt": "Números, expressões e equações"},
    "Brojevi, izrazi i jednačine.":{"en": "Numbers, expressions, and equations.", "de": "Zahlen, Terme und Gleichungen.", "fr": "Nombres, expressions et équations.", "es": "Números, expresiones y ecuaciones.", "it": "Numeri, espressioni ed equazioni.", "ru": "Числа, выражения и уравнения.", "pt": "Números, expressões e equações."},
    "Brojevi, izrazi, stepeni i logaritmi":{"en": "Numbers, expressions, powers, and logarithms", "de": "Zahlen, Terme, Potenzen und Logarithmen", "fr": "Nombres, expressions, puissances et logarithmes", "es": "Números, expresiones, potencias y logaritmos", "it": "Numeri, espressioni, potenze e logaritmi", "ru": "Числа, выражения, степени и логарифмы", "pt": "Números, expressões, potências e logaritmos"},
