    "Više promenljivih":{"en": "Multiple variables", "de": "Mehrere Variablen", "fr": "Plusieurs variables", "es": "Varias variables", "it": "Più variabili", "ru": "Несколько переменных", "pt": "Várias variáveis"},
    "Više promenljivih istog tipa može u jednom redu. ✔️":{"en": "Several variables of the same type can go in one line. ✔️", "de": "Mehrere Variablen desselben Typs können in einer Zeile stehen. ✔️", "fr": "Plusieurs variables du même type peuvent être déclarées sur une seule ligne. ✔️", "es": "Varias variables del mismo tipo pueden ir en una sola línea. ✔️", "it": "Più variabili dello stesso tipo possono stare su una sola riga. ✔️", "ru": "Несколько переменных одного типа можно объявить в одной строке. ✔️", "pt": "Várias variáveis do mesmo tipo podem ficar numa só linha. ✔️"},
    "Više slučajeva odjednom.":{"en": "Several cases at once.", "de": "Mehrere Fälle auf einmal.", "fr": "Plusieurs cas à la fois.", "es": "Varios casos a la vez.", "it": "Più casi contemporaneamente.", "ru": "Несколько случаев сразу.", "pt": "Vários casos ao mesmo tempo."},
    "Više stvari → millis.":{"en": "More things → millis.", "de": "Mehrere Dinge → millis.", "fr": "Plusieurs choses → millis.", "es": "Varias cosas → millis.", "it": "Più cose → millis.", "ru": "Несколько задач → millis.", "pt": "Várias coisas → millis."},
    "Višestruki integrali":{"en": "Multiple integrals", "de": "Mehrfachintegrale", "fr": "Intégrales multiples", "es": "Integrales múltiples", "it": "Integrali multipli", "ru": "Кратные интегралы", "pt": "Integrais múltiplos"},
