    "Vreme":{"en": "Time", "de": "Zeit", "fr": "Temps", "es": "Tiempo", "it": "Tempo", "ru": "Время", "pt": "Tempo"},
    "Vreme (delay, millis)":{"en": "Time (delay, millis)", "de": "Zeit (delay, millis)", "fr": "Temps (delay, millis)", "es": "Tiempo (delay, millis)", "it": "Tempo (delay, millis)", "ru": "Время (delay, millis)", "pt": "Tempo (delay, millis)"},
    "Vreme i petlje":{"en": "Time and loops", "de": "Zeit und Schleifen", "fr": "Temps et boucles", "es": "Tiempo y bucles", "it": "Tempo e cicli", "ru": "Время и циклы", "pt": "Tempo e loops"},
    "Vreme „teče sporije\" pri velikim brzinama.":{"en": "Time \"flows more slowly\" at high speeds.", "de": "Die Zeit „vergeht langsamer\" bei hohen Geschwindigkeiten.", "fr": "Le temps « s'écoule plus lentement » à grande vitesse.", "es": "El tiempo «transcurre más lento» a grandes velocidades.", "it": "Il tempo «scorre più lentamente» alle alte velocità.", "ru": "Время «течёт медленнее» при больших скоростях.", "pt": "O tempo «passa mais devagar» a grandes velocidades."},
    "Vremenska analiza (.tran)":{"en": "Transient analysis (.tran)", "de": "Transientenanalyse (.tran)", "fr": "Analyse temporelle (.tran)", "es": "Análisis transitorio (.tran)", "it": "Analisi transitoria (.tran)", "ru": "Временной анализ (.tran)", "pt": "Análise transitória (.tran)"},
    "Vrh vs početak.":{"en": "Top vs. start.", "de": "Oben vs. Anfang.", "fr": "Sommet vs début.", "es": "Cima vs. inicio.", "it": "Cima vs. inizio.", "ru": "Верх vs начало.", "pt": "Topo vs. início."},
