    "Zbir stepena čvorova = ?  a) |E|  b) 2|E|  c) |V|  d) 0":{"en": "Sum of node degrees = ?  a) |E|  b) 2|E|  c) |V|  d) 0", "de": "Summe der Knotengrade = ?  a) |E|  b) 2|E|  c) |V|  d) 0", "fr": "Somme des degrés des nœuds = ?  a) |E|  b) 2|E|  c) |V|  d) 0", "es": "Suma de los grados de los nodos = ?  a) |E|  b) 2|E|  c) |V|  d) 0", "it": "Somma dei gradi dei nodi = ?  a) |E|  b) 2|E|  c) |V|  d) 0", "ru": "Сумма степеней вершин = ?  a) |E|  b) 2|E|  c) |V|  d) 0", "pt": "Soma dos graus dos nós = ?  a) |E|  b) 2|E|  c) |V|  d) 0"},
