    "ispis. Bez njega MATLAB ispiše rezultat.":{"en": "print/display. Without it, MATLAB prints the result.", "de": "Ausgabe. Ohne sie gibt MATLAB das Ergebnis aus.", "fr": "affichage. Sans lui, MATLAB affiche le résultat.", "es": "salida/impresión. Sin ella, MATLAB imprime el resultado.", "it": "stampa. Senza di essa, MATLAB stampa il risultato.", "ru": "вывод. Без него MATLAB выводит результат.", "pt": "impressão. Sem ele, o MATLAB imprime o resultado."},
    "ispisuje na ekran, a":{"en": "prints to the screen, and", "de": "gibt auf dem Bildschirm aus, und", "fr": "affiche à l'écran, et", "es": "imprime en la pantalla, y", "it": "stampa a schermo, e", "ru": "выводит на экран, а", "pt": "imprime na tela, e"},
    "ispisuje u konzolu pregledača (F12).":{"en": "prints to the browser console (F12).", "de": "gibt in der Browser-Konsole aus (F12).", "fr": "affiche dans la console du navigateur (F12).", "es": "imprime en la consola del navegador (F12).", "it": "stampa nella console del browser (F12).", "ru": "выводит в консоль браузера (F12).", "pt": "imprime no console do navegador (F12)."},
    "ispisuje vrednost u Serial Monitor — tako vidiš šta senzor čita. ✔️":{"en": "prints the value to the Serial Monitor — that way you see what the sensor reads. ✔️", "de": "gibt den Wert im Serial Monitor aus — so siehst du, was der Sensor liest. ✔️", "fr": "affiche la valeur dans le Serial Monitor — comme ça tu vois ce que lit le capteur. ✔️", "es": "imprime el valor en el Serial Monitor — así ves lo que lee el sensor. ✔️", "it": "stampa il valore nel Serial Monitor — così vedi cosa legge il sensore. ✔️", "ru": "выводит значение в Serial Monitor — так ты видишь, что считывает датчик. ✔️", "pt": "imprime o valor no Serial Monitor — assim você vê o que o sensor está lendo. ✔️"},
    "ispiši vrednost":{"en": "print the value", "de": "gib den Wert aus", "fr": "affiche la valeur", "es": "imprime el valor", "it": "stampa il valore", "ru": "выведи значение", "pt": "imprima o valor"},
    "ispod prvog.":{"en": "below the first.", "de": "unter der ersten.", "fr": "sous le premier.", "es": "debajo del primero.", "it": "sotto il primo.", "ru": "под первым.", "pt": "abaixo do primeiro."},
    "ispod. 👇":{"en": "below. 👇", "de": "darunter. 👇", "fr": "en dessous. 👇", "es": "debajo. 👇", "it": "sotto. 👇", "ru": "ниже. 👇", "pt": "abaixo. 👇"},
