    "Pažnja: input uvek daje tekst":{"en": "Attention: input always returns text", "de": "Achtung: input liefert immer Text", "fr": "Attention : input renvoie toujours du texte", "es": "Atención: input siempre devuelve texto", "it": "Attenzione: input restituisce sempre testo", "ru": "Внимание: input всегда возвращает текст", "pt": "Atenção: input devolve sempre texto"},
    "Pažnja: kad množiš ili deliš negativnim brojem, znak nejednakosti se OKREĆE! ❤️":{"en": "Attention: when you multiply or divide by a negative number, the inequality sign FLIPS! ❤️", "de": "Achtung: Wenn du mit einer negativen Zahl multiplizierst oder dividierst, dreht sich das Ungleichheitszeichen UM! ❤️", "fr": "Attention : quand tu multiplies ou divises par un nombre négatif, le signe de l'inégalité S'INVERSE ! ❤️", "es": "Atención: cuando multiplicas o divides por un número negativo, ¡el signo de la desigualdad SE INVIERTE! ❤️", "it": "Attenzione: quando moltiplichi o dividi per un numero negativo, il segno della disuguaglianza SI INVERTE! ❤️", "ru": "Внимание: когда умножаешь или делишь на отрицательное число, знак неравенства МЕНЯЕТСЯ на противоположный! ❤️", "pt": "Atenção: quando multiplicas ou divides por um número negativo, o sinal da desigualdade INVERTE-SE! ❤️"},
    "Pažnja: m ≠ Meg!":{"en": "Attention: m ≠ Meg!", "de": "Achtung: m ≠ Meg!", "fr": "Attention : m ≠ Meg !", "es": "Atención: m ≠ Meg!", "it": "Attenzione: m ≠ Meg!", "ru": "Внимание: m ≠ Meg!", "pt": "Atenção: m ≠ Meg!"},
