    "Pravila i promena baze":{"en": "Rules and change of base", "de": "Regeln und Basiswechsel", "fr": "Règles et changement de base", "es": "Reglas y cambio de base", "it": "Regole e cambio di base", "ru": "Правила и смена основания", "pt": "Regras e mudança de base"},
    "Pravila izvođenja":{"en": "Differentiation rules", "de": "Ableitungsregeln", "fr": "Règles de dérivation", "es": "Reglas de derivación", "it": "Regole di derivazione", "ru": "Правила дифференцирования", "pt": "Regras de derivação"},
    "Pravila stepenovanja":{"en": "Exponent rules", "de": "Potenzregeln", "fr": "Règles des puissances", "es": "Reglas de las potencias", "it": "Regole delle potenze", "ru": "Правила возведения в степень", "pt": "Regras de potenciação"},
    "Pravila stepenovanja ubrzavaju račun.":{"en": "Exponent rules speed up calculations.", "de": "Potenzregeln beschleunigen die Rechnung.", "fr": "Les règles des puissances accélèrent le calcul.", "es": "Las reglas de las potencias agilizan el cálculo.", "it": "Le regole delle potenze velocizzano il calcolo.", "ru": "Правила возведения в степень ускоряют вычисления.", "pt": "As regras de potenciação agilizam o cálculo."},
    "Pravila znakova":{"en": "Sign rules", "de": "Vorzeichenregeln", "fr": "Règles des signes", "es": "Reglas de los signos", "it": "Regole dei segni", "ru": "Правила знаков", "pt": "Regras dos sinais"},
