    "Besplatan test":{"en": "Free test", "de": "Kostenloser Test", "fr": "Test gratuit", "es": "Test gratis", "it": "Test gratis", "ru": "Бесплатный тест", "pt": "Teste grátis"},
    "Konačno razumeš trigonometriju":{"en": "Finally get trigonometry", "de": "Endlich Trigonometrie verstehen", "fr": "Enfin comprendre la trigonométrie", "es": "Por fin entiendes la trigonometría", "it": "Finalmente capisci la trigonometria", "ru": "Наконец-то поймёшь тригонометрию", "pt": "Finalmente percebes a trigonometria"},
    "Bez bubanja — pomeriš tačku po kružnici i sve se sklopi.":{"en": "No cramming — move the point around the circle and it all clicks.", "de": "Kein Pauken — bewege den Punkt auf dem Kreis und alles ergibt Sinn.", "fr": "Sans bachotage — déplace le point sur le cercle et tout s'éclaire.", "es": "Sin empollar — mueve el punto por la circunferencia y todo encaja.", "it": "Niente studio a memoria — muovi il punto sul cerchio e tutto torna.", "ru": "Без зубрёжки — двигай точку по окружности, и всё складывается.", "pt": "Sem decorar — move o ponto no círculo e tudo encaixa."},
    "Otkrij šta da upišeš":{"en": "Discover what to study", "de": "Finde heraus, was du studieren sollst", "fr": "Découvre quoi étudier", "es": "Descubre qué estudiar", "it": "Scopri cosa studiare", "ru": "Узнай, куда поступать", "pt": "Descobre o que estudar"},
    "Škola, fakultet, tvoj smer — kratak test i topao, jasan rezultat.":{"en": "School, university, your path — a short test and a warm, clear result.", "de": "Schule, Studium, dein Weg — ein kurzer Test und ein warmes, klares Ergebnis.", "fr": "École, fac, ta voie — un test court et un résultat clair et bienveillant.", "es": "Escuela, carrera, tu camino — un test breve y un resultado cálido y claro.", "it": "Scuola, università, la tua strada — un test breve e un risultato chiaro e caloroso.", "ru": "Школа, вуз, твой путь — короткий тест и тёплый, ясный результат.", "pt": "Escola, faculdade, o teu rumo — um teste curto e um resultado claro e caloroso."},
