    "Mathia · Vizuelne lekcije":{"en": "Mathia · Visual lessons", "de": "Mathia · Visuelle Lektionen", "fr": "Mathia · Leçons visuelles", "es": "Mathia · Lecciones visuales", "it": "Mathia · Lezioni visive", "ru": "Mathia · Наглядные уроки", "pt": "Mathia · Lições visuais"},
    "Matematiku prvo vidiš, pa razumeš":{"en": "See math first, then understand it", "de": "Erst sehen, dann verstehen", "fr": "Vois les maths d'abord, comprends ensuite", "es": "Primero ves las matemáticas, luego las entiendes", "it": "Prima vedi la matematica, poi la capisci", "ru": "Сначала увидь математику — потом поймёшь", "pt": "Primeiro vês a matemática, depois entende-la"},
    "Interaktivne lekcije u kojima pojmovi žive — pomeraš, posmatraš i shvataš suštinu bez učenja napamet. Otvoreno, bez prijave.":{"en": "Interactive lessons where concepts come alive — you move, observe and grasp the essence without memorizing. Open, no sign-up.", "de": "Interaktive Lektionen, in denen Begriffe lebendig werden — du bewegst, beobachtest und verstehst das Wesentliche ohne Auswendiglernen. Offen, ohne Anmeldung.", "fr": "Des leçons interactives où les notions prennent vie — tu déplaces, observes et saisis l'essentiel sans apprendre par cœur. Ouvert, sans inscription.", "es": "Lecciones interactivas donde los conceptos cobran vida — mueves, observas y captas la esencia sin memorizar. Abierto, sin registro.", "it": "Lezioni interattive in cui i concetti prendono vita — muovi, osservi e cogli l'essenza senza imparare a memoria. Aperto, senza registrazione.", "ru": "Интерактивные уроки, где понятия оживают — двигаешь, наблюдаешь и схватываешь суть без зубрёжки. Открыто, без регистрации.", "pt": "Lições interativas onde os conceitos ganham vida — mexes, observas e apreendes a essência sem decorar. Aberto, sem registo."},
    "Nova lekcija":{"en": "New lesson", "de": "Neue Lektion", "fr": "Nouvelle leçon", "es": "Nueva lección", "it": "Nuova lezione", "ru": "Новый урок", "pt": "Nova lição"},
    "Trigonometrija koju možeš da vidiš":{"en": "Trigonometry you can see", "de": "Trigonometrie, die du sehen kannst", "fr": "La trigonométrie que tu peux voir", "es": "La trigonometría que puedes ver", "it": "La trigonometria che puoi vedere", "ru": "Тригонометрия, которую видно", "pt": "A trigonometria que podes ver"},
    "Jedinična kružnica, uglovi, radijani i funkcije sin(α), cos(α), tg(α), ctg(α) — mirno, korak po korak, dok ne razumeš baš sve.":{"en": "The unit circle, angles, radians and the functions sin(α), cos(α), tg(α), ctg(α) — calmly, step by step, until you understand it all.", "de": "Der Einheitskreis, Winkel, Bogenmaß und die Funktionen sin(α), cos(α), tg(α), ctg(α) — ruhig, Schritt für Schritt, bis du alles verstehst.", "fr": "Le cercle unité, les angles, les radians et les fonctions sin(α), cos(α), tg(α), ctg(α) — calmement, étape par étape, jusqu'à tout comprendre.", "es": "La circunferencia unidad, los ángulos, los radianes y las funciones sin(α), cos(α), tg(α), ctg(α) — con calma, paso a paso, hasta entenderlo todo.", "it": "La circonferenza unitaria, gli angoli, i radianti e le funzioni sin(α), cos(α), tg(α), ctg(α) — con calma, passo dopo passo, finché non capisci tutto.", "ru": "Единичная окружность, углы, радианы и функции sin(α), cos(α), tg(α), ctg(α) — спокойно, шаг за шагом, пока не поймёшь всё.", "pt": "O círculo unitário, os ângulos, os radianos e as funções sin(α), cos(α), tg(α), ctg(α) — com calma, passo a passo, até perceberes tudo."},
    "Jedinična kružnica":{"en": "Unit circle", "de": "Einheitskreis", "fr": "Cercle unité", "es": "Circunferencia unidad", "it": "Circonferenza unitaria", "ru": "Единичная окружность", "pt": "Círculo unitário"},
    "Radijani":{"en": "Radians", "de": "Bogenmaß", "fr": "Radians", "es": "Radianes", "it": "Radianti", "ru": "Радианы", "pt": "Radianos"},
