    "Kviz":{"en": "Quiz", "de": "Quiz", "fr": "Quiz", "es": "Cuestionario", "it": "Quiz", "ru": "Тест", "pt": "Quiz"},
    "Otvori lekciju →":{"en": "Open the lesson →", "de": "Lektion öffnen →", "fr": "Ouvrir la leçon →", "es": "Abrir la lección →", "it": "Apri la lezione →", "ru": "Открыть урок →", "pt": "Abrir a lição →"},
    "Uskoro":{"en": "Coming soon", "de": "Demnächst", "fr": "Bientôt", "es": "Próximamente", "it": "Presto", "ru": "Скоро", "pt": "Em breve"},
    "Još vizuelnih lekcija":{"en": "More visual lessons", "de": "Mehr visuelle Lektionen", "fr": "Plus de leçons visuelles", "es": "Más lecciones visuales", "it": "Altre lezioni visive", "ru": "Больше наглядных уроков", "pt": "Mais lições visuais"},
    "Pripremamo nove: funkcije i grafici, vektori, verovatnoća, geometrija u prostoru… Vraćaj se — učionica raste.":{"en": "We're preparing new ones: functions and graphs, vectors, probability, solid geometry… Come back — the classroom is growing.", "de": "Wir bereiten neue vor: Funktionen und Graphen, Vektoren, Wahrscheinlichkeit, Raumgeometrie… Schau wieder rein — das Klassenzimmer wächst.", "fr": "Nous en préparons de nouvelles : fonctions et graphiques, vecteurs, probabilités, géométrie dans l'espace… Reviens — la salle de classe grandit.", "es": "Estamos preparando nuevas: funciones y gráficas, vectores, probabilidad, geometría del espacio… Vuelve — el aula crece.", "it": "Ne stiamo preparando di nuove: funzioni e grafici, vettori, probabilità, geometria nello spazio… Torna — l'aula cresce.", "ru": "Готовим новые: функции и графики, векторы, вероятность, стереометрия… Возвращайся — класс растёт.", "pt": "Estamos a preparar novas: funções e gráficos, vetores, probabilidade, geometria no espaço… Volta — a sala de aula cresce."},
    "Mathia · Pronađi svoj smer":{"en": "Mathia · Find your path", "de": "Mathia · Finde deinen Weg", "fr": "Mathia · Trouve ta voie", "es": "Mathia · Encuentra tu camino", "it": "Mathia · Trova la tua strada", "ru": "Mathia · Найди свой путь", "pt": "Mathia · Encontra o teu rumo"},
    "Pronađi svoj smer":{"en": "Find your path", "de": "Finde deinen Weg", "fr": "Trouve ta voie", "es": "Encuentra tu camino", "it": "Trova la tua strada", "ru": "Найди свой путь", "pt": "Encontra o teu rumo"},
    "Kratki, besplatni testovi ti pomažu da otkriješ koja škola, koji fakultet i koji način učenja ti najviše odgovaraju.":{"en": "Short, free tests help you discover which school, which university and which way of learning suit you best.", "de": "Kurze, kostenlose Tests helfen dir herauszufinden, welche Schule, welches Studium und welche Lernweise am besten zu dir passen.", "fr": "De courts tests gratuits t'aident à découvrir quelle école, quelle faculté et quelle façon d'apprendre te conviennent le mieux.", "es": "Tests breves y gratuitos te ayudan a descubrir qué escuela, qué carrera y qué forma de aprender te van mejor.", "it": "Brevi test gratuiti ti aiutano a scoprire quale scuola, quale facoltà e quale modo di studiare fanno per te.", "ru": "Короткие бесплатные тесты помогут понять, какая школа, какой факультет и какой способ учёбы подходят тебе больше всего.", "pt": "Testes curtos e gratuitos ajudam-te a descobrir que escola, que faculdade e que forma de aprender combinam melhor contigo."},
    "Besplatno · bez registracije":{"en": "Free · no sign-up", "de": "Kostenlos · ohne Anmeldung", "fr": "Gratuit · sans inscription", "es": "Gratis · sin registro", "it": "Gratis · senza registrazione", "ru": "Бесплатно · без регистрации", "pt": "Grátis · sem registo"},
    "Rezultat je smernica, ne presuda — služi da lakše razmišljaš o svom putu. 💛":{"en": "The result is a guide, not a verdict — it's there to help you think about your path. 💛", "de": "Das Ergebnis ist ein Wegweiser, kein Urteil — es hilft dir, über deinen Weg nachzudenken. 💛", "fr": "Le résultat est un repère, pas un verdict — il t'aide à réfléchir à ta voie. 💛", "es": "El resultado es una guía, no un veredicto — sirve para ayudarte a pensar en tu camino. 💛", "it": "Il risultato è una guida, non un verdetto — serve ad aiutarti a riflettere sul tuo percorso. 💛", "ru": "Результат — это ориентир, а не приговор — он помогает подумать о своём пути. 💛", "pt": "O resultado é uma orientação, não um veredito — serve para te ajudar a pensar no teu rumo. 💛"},
    "← Svi testovi":{"en": "← All tests", "de": "← Alle Tests", "fr": "← Tous les tests", "es": "← Todos los tests", "it": "← Tutti i test", "ru": "← Все тесты", "pt": "← Todos os testes"},
    "Vidi rezultat →":{"en": "See result →", "de": "Ergebnis ansehen →", "fr": "Voir le résultat →", "es": "Ver resultado →", "it": "Vedi il risultato →", "ru": "Смотреть результат →", "pt": "Ver resultado →"},
    "↻ Uradi ponovo":{"en": "↻ Try again", "de": "↻ Nochmal", "fr": "↻ Recommencer", "es": "↻ Repetir", "it": "↻ Rifai", "ru": "↻ Пройти снова", "pt": "↻ Repetir"},
    "Drugi test →":{"en": "Another test →", "de": "Anderer Test →", "fr": "Autre test →", "es": "Otro test →", "it": "Altro test →", "ru": "Другой тест →", "pt": "Outro teste →"},

