    "Ekonomska \u0161kola":{en:"Business school",de:"Wirtschaftsschule",fr:"Lyc\u00e9e d'\u00e9conomie",es:"Escuela de econom\u00eda",it:"Istituto economico",ru:"\u042d\u043a\u043e\u043d\u043e\u043c\u0438\u0447\u0435\u0441\u043a\u0430\u044f \u0448\u043a\u043e\u043b\u0430",pt:"Escola de economia"},
    "Rano u\u010di\u0161 kako posao i novac funkcioni\u0161u.":{en:"You learn early how business and money work.",de:"Du lernst fr\u00fch, wie Gesch\u00e4ft und Geld funktionieren.",fr:"Tu apprends t\u00f4t comment fonctionnent le business et l'argent.",es:"Aprendes pronto c\u00f3mo funcionan los negocios y el dinero.",it:"Impari presto come funzionano affari e denaro.",ru:"\u0422\u044b \u0440\u0430\u043d\u043e \u0443\u0447\u0438\u0448\u044c\u0441\u044f, \u043a\u0430\u043a \u0440\u0430\u0431\u043e\u0442\u0430\u044e\u0442 \u0431\u0438\u0437\u043d\u0435\u0441 \u0438 \u0434\u0435\u043d\u044c\u0433\u0438.",pt:"Aprendes cedo como funcionam o neg\u00f3cio e o dinheiro."},
    "Pravno-birotehni\u010dka \u0161kola":{en:"Law and administration school",de:"Rechts- und B\u00fcrofachschule",fr:"Lyc\u00e9e de droit et de bureautique",es:"Escuela jur\u00eddico-administrativa",it:"Istituto giuridico-amministrativo",ru:"\u042e\u0440\u0438\u0434\u0438\u0447\u043d\u043e-\u0434\u0435\u043b\u043e\u043f\u0440\u043e\u0438\u0437\u0432\u043e\u0434\u0441\u0442\u0432\u0435\u043d\u043d\u0430\u044f \u0448\u043a\u043e\u043b\u0430",pt:"Escola jur\u00eddico-administrativa"},
    "Turisti\u010dka / ugostiteljska \u0161kola":{en:"Tourism / hospitality school",de:"Tourismus- / Gastgewerbeschule",fr:"Lyc\u00e9e du tourisme / de l'h\u00f4tellerie",es:"Escuela de turismo / hosteler\u00eda",it:"Istituto per il turismo / l'ospitalit\u00e0",ru:"\u0422\u0443\u0440\u0438\u0441\u0442\u0438\u0447\u0435\u0441\u043a\u043e-\u0433\u043e\u0441\u0442\u0438\u043d\u0438\u0447\u043d\u0430\u044f \u0448\u043a\u043e\u043b\u0430",pt:"Escola de turismo / hotelaria"},
