    "Matematika \u00b7 Fizika \u00b7 Elektrotehnika":{en:"Mathematics \u00b7 Physics \u00b7 Electrical engineering",de:"Mathematik \u00b7 Physik \u00b7 Elektrotechnik",fr:"Math\u00e9matiques \u00b7 Physique \u00b7 \u00c9lectrotechnique",es:"Matem\u00e1ticas \u00b7 F\u00edsica \u00b7 Electrotecnia",it:"Matematica \u00b7 Fisica \u00b7 Elettrotecnica",ru:"\u041c\u0430\u0442\u0435\u043c\u0430\u0442\u0438\u043a\u0430 \u00b7 \u0424\u0438\u0437\u0438\u043a\u0430 \u00b7 \u042d\u043b\u0435\u043a\u0442\u0440\u043e\u0442\u0435\u0445\u043d\u0438\u043a\u0430",pt:"Matem\u00e1tica \u00b7 F\u00edsica \u00b7 Eletrotecnia"},
